SECTION_LABELS = {
    "de": {"details": "Produktdetails", "materials": "Materialien", "highlights": "Besonderheiten"},
    "no": {"details": "Produktdetaljer", "materials": "Materialer", "highlights": "Særtrekk"},
    "ro": {"details": "Detalii produs", "materials": "Materiale", "highlights": "Caracteristici"},
    "ru": {"details": "Детали товара", "materials": "Материалы", "highlights": "Особенности"},
}

def main():
    for locale in ["de", "no", "ro", "ru"]:
        path = os.path.join(LOCALES_DIR, locale, "home.json")
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)

        products = data["catalog"]["products"]
        assert len(products) == 37, f"Expected 37 products in {locale}, got {len(products)}"

        labels = SECTION_LABELS[locale]
        for i, product in enumerate(products):
            s = SPECS[i][locale]
            product["specs"] = {
                "detailsLabel": labels["details"],
                "materialsLabel": labels["materials"],
                "highlightsLabel": labels["highlights"],
                "details": s["details"],
                "materials": s["materials"],
                "highlights": s["highlights"],
            }

        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
        print(f"Updated {locale}/home.json")

if __name__ == "__main__":
    main()
